import heapq
class Solution:
    def largestSumAfterKNegations(self, nums, k):
        h = list(nums)
        heapq.heapify(h)
        for _ in range(k):
            x = heapq.heappop(h)
            heapq.heappush(h, -x)
        return sum(h)

