var largestSumAfterKNegations = function(nums, k) {
    nums.sort((a, b) => a - b);
    let i = 0;
    const n = nums.length;
    while (i < n && k > 0 && nums[i] < 0) {
        nums[i] = -nums[i];
        i++;
        k--;
    }
    let total = nums.reduce((a, b) => a + b, 0);
    if (k % 2 === 1) {
        total -= 2 * Math.min(...nums);
    }
    return total;
};
